// ---- CONFIG (placeholders, replaced by sync to live n8n) ----
const TELEGRAM_BOT_TOKEN = 'YOUR_TELEGRAM_BOT_TOKEN';
const ALLOWED_CHAT_IDS = [935389847];
const LAUNCHER_URL = 'http://10.1.4.232:8765';
const LAUNCHER_SECRET = 'YOUR_LAUNCHER_SECRET';
const MLFLOW_URL = 'http://10.1.4.230:5000';
const RUNPOD_API_KEY = 'YOUR_RUNPOD_API_KEY';
const RUNPOD_POD_ID = 'YOUR_RUNPOD_POD_ID';

// ---- POLL TELEGRAM getUpdates (long-poll style) ----
// Use staticData to track the last update_id we processed across executions.
const staticData = $getWorkflowStaticData('global');
const lastOffset = staticData.lastOffset || 0;

let updates = [];
try {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/getUpdates`,
    qs: { offset: lastOffset + 1, timeout: 0, allowed_updates: 'message' },
    json: true,
    timeout: 8000,
  });
  if (r.ok && Array.isArray(r.result)) updates = r.result;
} catch (e) {
  // Telegram down or transient — skip this tick
  return [];
}

if (updates.length === 0) return [];

// Advance offset BEFORE processing so a slow handler can't infinite-loop.
staticData.lastOffset = Math.max(...updates.map(u => u.update_id));

// ---- HELPERS ----
async function gqlRunPod(query) {
  return await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.runpod.io/graphql',
    headers: {
      'Authorization': `Bearer ${RUNPOD_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: { query },
    json: true,
    timeout: 8000,
  });
}

async function getRunPodStatus() {
  try {
    const q = `query { pod(input: {podId: "${RUNPOD_POD_ID}"}) { id name desiredStatus costPerHr runtime { uptimeInSeconds gpus { gpuUtilPercent memoryUtilPercent } } } }`;
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.runpod.io/graphql',
      headers: { 'Authorization': `Bearer ${RUNPOD_API_KEY}`, 'Content-Type': 'application/json' },
      body: { query: q },
      json: true,
      timeout: 8000,
    });
    return r.data?.pod;
  } catch (e) {
    return { _error: String(e).slice(0, 200) };
  }
}

async function getLauncherStatus() {
  try {
    return await this.helpers.httpRequest({ url: `${LAUNCHER_URL}/status`, json: true, timeout: 5000 });
  } catch (e) {
    return { _error: 'launcher unreachable' };
  }
}

async function getMLflowRecent(n=3) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: `${MLFLOW_URL}/api/2.0/mlflow/runs/search`,
      headers: { 'Content-Type': 'application/json' },
      body: { experiment_ids: ['1','2'], max_results: n, order_by: ['start_time DESC'] },
      json: true,
      timeout: 5000,
    });
    return r.runs || [];
  } catch (e) {
    return [];
  }
}

function fmtUptime(seconds) {
  if (!seconds) return '0s';
  const h = Math.floor(seconds/3600);
  const m = Math.floor((seconds%3600)/60);
  const s = seconds%60;
  return h ? `${h}h${m}m` : (m ? `${m}m${s}s` : `${s}s`);
}

function fmtRunPod(pod) {
  if (!pod) return 'pod not found';
  if (pod._error) return `error: ${pod._error}`;
  const rt = pod.runtime;
  if (!rt) return `pod ${pod.desiredStatus} (no runtime)`;
  const g = rt.gpus?.[0] || {};
  const cost = (rt.uptimeInSeconds * pod.costPerHr / 3600).toFixed(2);
  return `*${pod.name}* ${pod.desiredStatus}\n  uptime: ${fmtUptime(rt.uptimeInSeconds)}  cost: \\$${cost}\n  gpu: ${g.gpuUtilPercent ?? '?'}%  mem: ${g.memoryUtilPercent ?? '?'}%`;
}

function fmtETA(seconds) {
  if (!seconds || seconds < 0 || !isFinite(seconds)) return '?';
  if (seconds < 60) return `${Math.round(seconds)}s`;
  const h = Math.floor(seconds/3600);
  const m = Math.round((seconds%3600)/60);
  return h ? `${h}h${m}m` : `${m}m`;
}

function fmtMLflowRuns(runs) {
  if (!runs.length) return '_no recent runs_';
  return runs.map(r => {
    const m = (r.data?.metrics || []).reduce((a,x) => (a[x.key]=x.value, a), {});
    const p = (r.data?.params || []).reduce((a,x) => (a[x.key]=x.value, a), {});
    const name = (r.info.run_name || '?').slice(0,30);
    const sts = r.info.status;
    const ts = m.timesteps;
    const total = parseFloat(p.total_timesteps);
    const sps = m.steps_per_s;
    const rew = m.rollout_ep_rew_mean;
    const succ = m.final_overall_success_rate;
    const dev = p.device;
    let line = `\`${name}\` ${sts}`;
    if (ts != null && total > 0) {
      const pct = (ts / total * 100).toFixed(0);
      line += `  ${(ts/1000).toFixed(0)}K/${(total/1e6).toFixed(0)}M (${pct}%)`;
      if (sts === 'RUNNING' && sps > 0) {
        const eta = (total - ts) / sps;
        line += ` ETA ${fmtETA(eta)}`;
      }
    } else if (ts != null) {
      line += `  ${(ts/1000).toFixed(0)}K steps`;
    }
    if (rew != null) line += `  rew=${rew.toFixed(0)}`;
    if (succ != null) line += `  *succ=${(succ*100).toFixed(0)}%*`;
    if (dev && dev !== '?') line += `  [${dev}]`;
    return '  ' + line;
  }).join('\n');
}

async function handleCommand(message) {
  const chat_id = message.chat?.id;
  const text = (message.text || '').trim();
  if (!ALLOWED_CHAT_IDS.includes(chat_id)) {
    return { chat_id, text: `Unauthorized chat_id: ${chat_id}` };
  }
  const tokens = text.split(/\s+/);
  const cmd = tokens[0].toLowerCase();
  const args = tokens.slice(1);
  let reply = '';

  if (cmd === '/start' || cmd === '/help') {
    reply = `*Triple Pendulum Bot* — commands:\n\n` +
      `\`/status\` — overall pipeline\n` +
      `\`/runpod\` — RunPod pod state + GPU + cost\n` +
      `\`/ct1018\` — local launcher (active sessions)\n` +
      `\`/mlflow [n]\` — last n MLflow runs\n` +
      `\`/gpu\` — RunPod GPU one-liner\n` +
      `\`/launch m3b|m3c|m4|m2\` — launch on CT 1018\n` +
      `\`/pod_start\` — resume RunPod pod\n` +
      `\`/pod_stop\` — stop RunPod pod\n` +
      `\`/help\` — this message`;
  }
  else if (cmd === '/status') {
    const [pod, launcher, runs] = await Promise.all([
      getRunPodStatus.call(this),
      getLauncherStatus.call(this),
      getMLflowRecent.call(this, 3),
    ]);
    reply = `*Triple Pendulum status*\n\n` +
      `🌐 *RunPod*\n${fmtRunPod(pod)}\n\n` +
      `🖥 *CT 1018 launcher*\n  ${launcher._error ? launcher._error : `${launcher.count || 0} active processes`}\n\n` +
      `📊 *MLflow* (latest)\n${fmtMLflowRuns(runs)}`;
  }
  else if (cmd === '/runpod') {
    const pod = await getRunPodStatus.call(this);
    reply = `🌐 *RunPod*\n${fmtRunPod(pod)}`;
  }
  else if (cmd === '/ct1018') {
    const launcher = await getLauncherStatus.call(this);
    if (launcher._error) {
      reply = `🖥 *CT 1018* — ${launcher._error}`;
    } else {
      const sessions = (launcher.sessions || []).slice(0,3).map(s => `  • \`${s.slice(0,80)}\``).join('\n');
      reply = `🖥 *CT 1018* — ${launcher.count} active\n${sessions || '  _none_'}`;
    }
  }
  else if (cmd === '/mlflow') {
    const n = parseInt(args[0]) || 3;
    const runs = await getMLflowRecent.call(this, Math.min(n, 10));
    reply = `📊 *MLflow* — last ${runs.length}\n${fmtMLflowRuns(runs)}`;
  }
  else if (cmd === '/gpu') {
    const pod = await getRunPodStatus.call(this);
    if (!pod || pod._error) reply = `RunPod: ${pod?._error || 'not reachable'}`;
    else {
      const g = pod.runtime?.gpus?.[0];
      reply = g ? `GPU ${g.gpuUtilPercent}% util / ${g.memoryUtilPercent}% mem` : 'no runtime';
    }
  }
  else if (cmd === '/launch') {
    const stage = (args[0] || '').toLowerCase();
    const stageMap = {
      'm2':  { module: 'training.train_m2_upright',     config: 'training/configs/m2_upright_tqc.yaml' },
      'm3b': { module: 'training.train_m3_all_eps',     config: 'training/configs/m3b_all_eps_tqc.yaml' },
      'm3c': { module: 'training.train_m3_all_eps',     config: 'training/configs/m3c_all_eps_tqc.yaml' },
      'm4':  { module: 'training.train_m4_transitions', config: 'training/configs/m4_transitions_tqc.yaml' },
    };
    if (!stageMap[stage]) {
      reply = `Unknown stage: \`${stage}\`\nValid: m2, m3b, m3c, m4`;
    } else {
      try {
        const r = await this.helpers.httpRequest({
          method: 'POST',
          url: `${LAUNCHER_URL}/launch`,
          headers: { 'Content-Type': 'application/json' },
          body: { secret: LAUNCHER_SECRET, ...stageMap[stage] },
          json: true,
          timeout: 15000,
        });
        reply = r.ok
          ? `✅ Launched *${stage.toUpperCase()}*\nsession: \`${r.session}\``
          : `❌ Launch failed: ${r.error || JSON.stringify(r)}`;
      } catch (e) {
        reply = `❌ Launcher error: ${String(e).slice(0,200)}`;
      }
    }
  }
  else if (cmd === '/pod_start') {
    try {
      const r = await gqlRunPod.call(this, `mutation { podResume(input: {podId: "${RUNPOD_POD_ID}", gpuCount: 1}) { id desiredStatus } }`);
      const s = r.data?.podResume?.desiredStatus;
      reply = s ? `🌐 RunPod resumed: *${s}*` : `❌ resume failed`;
    } catch (e) { reply = `❌ ${String(e).slice(0,200)}`; }
  }
  else if (cmd === '/pod_stop') {
    try {
      const r = await gqlRunPod.call(this, `mutation { podStop(input: {podId: "${RUNPOD_POD_ID}"}) { id desiredStatus } }`);
      const s = r.data?.podStop?.desiredStatus;
      reply = s ? `🌐 RunPod stopped: *${s}*` : `❌ stop failed`;
    } catch (e) { reply = `❌ ${String(e).slice(0,200)}`; }
  }
  else {
    reply = `Unknown command: \`${cmd}\`\nTry \`/help\``;
  }
  return { chat_id, text: reply };
}

// Process all updates serially. Each update produces ONE outgoing message.
const items = [];
for (const upd of updates) {
  const msg = upd.message;
  if (!msg || !msg.text) continue;
  const r = await handleCommand.call(this, msg);
  items.push({ json: { ...r, parse_mode: 'Markdown', disable_web_page_preview: true, telegramBotUrl: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage` } });
}
return items;
